    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        final int[] counts = new int[3];
        KVStore s = new KVStore();
        s.addObserver(new KVStoreObserver() {
            public void onSet(String k, String v, long t) { counts[0]++; }
            public void onDelete(String k) { counts[1]++; }
            public void onExpire(String k) { counts[2]++; }
        });
        s.set("a", "1");
        s.set("b", "2");
        s.delete("a");
        if (counts[0] == 2 && counts[1] == 1) System.out.println("OK_OBSERVER");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        KVStore s = new KVStore(new AppendOnlyLogPersistence());
        s.set("x", "1");
        s.set("y", "2");
        s.delete("x");
        if (s.getLog().size() == 3) System.out.println("OK_LOG_SIZE");
        Command first = s.getLog().get(0);
        if (first.getType() == Command.Type.SET && "x".equals(first.getKey())) System.out.println("OK_LOG_CONTENT");
    }
}

